{"code": "import json
import re

# Load LGG patients data
lgg_patients = var_functions.query_db_28
if isinstance(lgg_patients, str) and lgg_patients.endswith('.json'):
    with open(lgg_patients, 'r') as f:
        lgg_data = json.load(f)
else:
    lgg_data = lgg_patients

print('Total LGG patients:', len(lgg_data))

# Extract patient barcodes and histological types
patient_map = {}
for record in lgg_data:
    desc = record.get('Patient_description', '')
    hist_type = record.get('histological_type', '')

    # Skip bracketed histology types
    if hist_type.startswith('[') and hist_type.endswith(']'):
        continue

    # Extract barcode
    match = re.search(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', desc)
    if match:
        barcode = match.group(1)
        patient_map[barcode] = hist_type

print('Valid LGG patients:', len(patient_map))
print('Sample:', list(patient_map.items())[:3])

# Get IGF2 expression data
igf2_file = var_functions.query_db_26
if isinstance(igf2_file, str) and igf2_file.endswith('.json'):
    with open(igf2_file, 'r') as f:
        igf2_data = json.load(f)
else:
    igf2_data = igf2_file

print('Total IGF2 expression records:', len(igf2_data))

# Filter IGF2 data for LGG patients
lgg_igf2 = []
for record in igf2_data:
    barcode = record.get('ParticipantBarcode')
    if barcode in patient_map:
        lgg_igf2.append({
            'ParticipantBarcode': barcode,
            'histological_type': patient_map[barcode],
            'normalized_count': float(record.get('normalized_count', 0))
        })

print('LGG patients with IGF2 data:', len(lgg_igf2))

# Group by histological type and compute average log10 expression
from collections import defaultdict
import math

hist_groups = defaultdict(list)
for item in lgg_igf2:
    hist_groups[item['histological_type']].append(item['normalized_count'])

results = {}
for hist_type, counts in hist_groups.items():
    log10_vals = [math.log10(c + 1) for c in counts]
    avg_log10 = sum(log10_vals) / len(log10_vals)
    results[hist_type] = {
        'count': len(counts),
        'avg_log10_expression': round(avg_log10, 4)
    }

print('\nResults by histological type:')
for hist_type, stats in sorted(results.items()):
    print(f"  {hist_type}: n={stats['count']}, avg_log10={stats['avg_log10_expression']}")

output = {'results': results, 'total_patients': len(lgg_igf2)}
print('__RESULT__:')
print(json.dumps(output))"}

