{"code": "import json, re, math
from collections import defaultdict

# Load clinical data
clinical_file = var_functions.query_db_40
if isinstance(clinical_file, str) and clinical_file.endswith('.json'):
    with open(clinical_file, 'r') as f:
        clinical_data = json.load(f)
else:
    clinical_data = clinical_file

# Build patient map with strict LGG histological types
valid_hist_types = {'Oligodendroglioma', 'Oligoastrocytoma', 'Astrocytoma'}
patient_map = {}

for record in clinical_data:
    desc = record.get('Patient_description', '')
    hist_type = record.get('histological_type', '')

    if hist_type not in valid_hist_types:
        continue

    match = re.search(r'(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})', desc)
    if match:
        patient_map[match.group(1)] = hist_type

# Load IGF2 expression data
igf2_file = var_functions.query_db_26
if isinstance(igf2_file, str) and igf2_file.endswith('.json'):
    with open(igf2_file, 'r') as f:
        igf2_data = json.load(f)
else:
    igf2_data = igf2_file

# Filter and compute average log10 expression
hist_groups = defaultdict(list)
for record in igf2_data:
    barcode = record.get('ParticipantBarcode')
    if barcode in patient_map:
        try:
            count = float(record.get('normalized_count', 0))
            log_val = math.log10(count + 1)
            hist_groups[patient_map[barcode]].append(log_val)
        except (ValueError, TypeError):
            continue

# Calculate means with 4 decimal places
results = {}
summary_stats = {}
for hist_type, log_vals in hist_groups.items():
    if log_vals:
        avg_log10 = sum(log_vals) / len(log_vals)
        results[hist_type] = round(avg_log10, 4)
        summary_stats[hist_type] = {
            'count': len(log_vals),
            'avg_log10': round(avg_log10, 4)
        }

print('Summary Statistics:')
for hist_type, stats in sorted(summary_stats.items()):
    print(f"  {hist_type}: n={stats['count']}, avg_log10_expression={stats['avg_log10']}")

print('\nFinal Results:')
print('__RESULT__:')
print(json.dumps(results))"}

